import sys

def main():
    data = sys.stdin.buffer.read().split()
    idx = 0
    n = int(data[idx]); m = int(data[idx+1]); idx += 2
    grid = []
    for _ in range(n):
        grid.append(data[idx].decode()); idx += 1
    q = int(data[idx]); idx += 1
    queries = []
    for _ in range(q):
        x1 = int(data[idx]); x2 = int(data[idx+1]); idx += 2
        queries.append((x1-1, x2-1))

    # For each column, find first and last row with 'X'
    first_X = [n] * m  # n means no X
    last_X = [-1] * m  # -1 means no X
    for x in range(m):
        for y in range(n):
            if grid[y][x] == 'X':
                if first_X[x] == n:
                    first_X[x] = y
                last_X[x] = y

    # Column x (x >= 1) is bad if first_X[x-1] <= last_X[x]
    # i.e., column x-1 has an X at or above the last X in column x
    bad = [0] * m
    for x in range(1, m):
        if last_X[x] >= 0 and first_X[x-1] <= last_X[x]:
            bad[x] = 1

    # prefix sum of bad
    prefix = [0] * (m + 1)
    for x in range(m):
        prefix[x+1] = prefix[x] + bad[x]

    out = []
    for x1, x2 in queries:
        # bad columns in range (x1, x2] i.e. x1+1 to x2
        count = prefix[x2+1] - prefix[x1+1]
        out.append("YES" if count == 0 else "NO")

    print('\n'.join(out))

if __name__ == "__main__":
    main()

